function 剑会活动定时器()
    if not 剑会天下开关 then
        if 剑会单人活动时间.日期=="每天" then
            if 剑会单人活动时间.时==服务端参数.小时+0 and 剑会单人活动时间.分==服务端参数.分钟+0 and 剑会单人活动时间.秒<=服务端参数.秒+0  then
                任务处理类.开启剑会天下("单人")
            end
        elseif 剑会单人活动时间.大写日期 == "每月" then
            local currentDate = tonumber(os.date("*t"))
            if currentDate == 1 then
                if 剑会单人活动时间.时==服务端参数.小时+0 and 剑会单人活动时间.分==服务端参数.分钟+0 and 剑会单人活动时间.秒<=服务端参数.秒+0 then
                    任务处理类.开启剑会天下("单人")
                end
            end
        elseif 剑会单人活动时间.大写日期 == "半月" then
            local currentDate = tonumber(os.date("*t"))
            if currentDate == 1 or currentDate == 15 then
                if 剑会单人活动时间.时==服务端参数.小时+0 and 剑会单人活动时间.分==服务端参数.分钟+0 and 剑会单人活动时间.秒<=服务端参数.秒+0 then
                    任务处理类.开启剑会天下("单人")
                end
            end
        else
            local zhouji=tonumber(os.date("%w", os.time()))
            if zhouji == tonumber(剑会单人活动时间.日期) then
                if 剑会单人活动时间.时==服务端参数.小时+0 and 剑会单人活动时间.分==服务端参数.分钟+0 and 剑会单人活动时间.秒<=服务端参数.秒+0  then
                    任务处理类.开启剑会天下("单人")
