                    任务处理类.开启剑会天下("五人")
                end
            end
        end
    elseif 剑会天下开始时间 then
        if 剑会天下开始时间 - os.time() <= 0 then
            剑会天下开始时间 = nil
            任务处理类.关闭剑会天下()
        end
