end

function 取剑会天下数据(id)
  if 剑会天下[id]==nil then
    剑会天下[id]={当前积分=1200,连胜=0,名称=玩家数据[id].角色.名称,等级=玩家数据[id].角色.等级,id=id,门派=玩家数据[id].角色.门派}
  end
end

