function 任务处理类.开启剑会天下(类型)
    剑会天下开关 = true
    剑会天下开始时间 = os.time() + 7200
    if 类型 == "单人" then--"#Y
        剑会天下单人匹配开关 = true
    elseif 类型 == "三人" then--"#Y
        剑会天下三人匹配开关 = true
    elseif 类型 == "五人" then--"#Y
        剑会天下五人匹配开关 = true
    end
    广播消息({内容="#Y剑会天下"..类型.."活动已经开启#24,#Y/参加的玩家可以参加PK战斗了！",频道="xt"})
