function 任务处理类.剑会天下积分差异(胜利id,失败id)
    --计算分差值按照每相差100分 做递增递减
    local 胜利组平均分 = 0
    local 失败组平均分 = 0
    local 胜利基础分 = 40
    local 失败基础分 = 12
    local 分差值 = 0
    if 胜利id~=0 then
        if 玩家数据[胜利id].队伍~=0 then
            local 队伍id=玩家数据[胜利id].队伍
            for n=1,#队伍数据[队伍id].成员数据 do
                local 队员id=队伍数据[队伍id].成员数据[n]
                胜利组平均分 = 胜利组平均分 + 剑会天下[队员id].当前积分
            end
            胜利组平均分 = math.floor(胜利组平均分 / #队伍数据[队伍id].成员数据)
        else
            胜利组平均分 = 剑会天下[胜利id].当前积分
        end
    end
    if 失败id and 失败id~=0 then
        if 玩家数据[失败id].队伍~=0 then
            local 队伍id=玩家数据[失败id].队伍
            for n=1,#队伍数据[队伍id].成员数据 do
                local 队员id=队伍数据[队伍id].成员数据[n]
                失败组平均分 = 失败组平均分 + 剑会天下[队员id].当前积分
            end
            失败组平均分 = math.floor(失败组平均分 / #队伍数据[队伍id].成员数据)
        else
            失败组平均分=剑会天下[失败id].当前积分
        end
    end
    if 胜利id == 0 then
        胜利组平均分 = 失败组平均分
    end
    if 失败id == nil or 失败id == 0 then
        失败组平均分 = 胜利组平均分
    end
    分差值 = 胜利组平均分 - 失败组平均分
    if 分差值<0 then  --低分打赢高分的情况下
        if math.abs(分差值) >100 then
            local 增加值 = math.floor(math.abs(分差值)/100) * 2
            if 增加值 >= 10 then
                增加值 = 10
            end
            胜利基础分 = 胜利基础分 + 增加值
            失败基础分 = 失败基础分 + 增加值
        end
    else  --高分打赢低分的情况下
        if math.abs(分差值) >100 then
            local 增加值 = math.floor(math.abs(分差值)/100) * 2
            if 增加值 >= 10 then
                增加值 = 10
            end
            胜利基础分 = 胜利基础分 - 增加值
            失败基础分 = 失败基础分 - 增加值
        end
    end
    return {胜利基础分,失败基础分}
end

function 任务处理类.剑会天下奖励结算(id,类型)
    if 剑会天下次数统计[id] == nil then
        剑会天下次数统计[id] = {次数=0,首胜=false}
    end
    if 剑会天下次数统计[id].次数 <= 2 then
        剑会天下次数统计[id].次数 = 剑会天下次数统计[id].次数 + 1
        --根据ID发放奖励
    end
    if 剑会天下次数统计[id].首胜 == false then
        剑会天下次数统计[id].首胜 = true
        --每天首胜发放奖励
    end
    --连胜增加积分
    if 类型 then
        战斗奖励:其他奖励(id,类型)
    end
    if 剑会天下[id].连胜 == 3 then
        广播消息({内容=format("#S(剑会天下)#Y/恭喜 #R/%s #Y在活动中连胜三场！",玩家数据[id].角色.名称),频道="xt"})
    elseif 剑会天下[id].连胜 == 6 then
        广播消息({内容=format("#S(剑会天下)#Y/恭喜 #R/%s #Y在活动中连胜六场！",玩家数据[id].角色.名称),频道="xt"})
    elseif 剑会天下[id].连胜 == 9 then
        剑会天下[id].连胜=0
        广播消息({内容=format("#S(剑会天下)#Y/恭喜 #R/%s #Y在活动中连胜九场！",玩家数据[id].角色.名称),频道="xt"})
    end
end


